### GraphQL Architecture & Configuration

**From `/private/tmp/claude-eval-embed-20260226-142750/light-embed/.claude/skills/graphql-skill/SKILL.md`:**

#### GraphQL Schema Definition
**Location**: `graphql/src/main/resources/graphql/schema.graphqls` or separate `.graphqls` file

```graphql
type Feature {
    id: ID!
    name: String!
    user: SimpleUser
    createdAt: String!
}

input CreateFeatureInput {
    name: String!
}

extend type Query {
    feature(featureId: ID!): Feature
    features(limit: Int, offset: Int): [Feature!]!
}

extend type Mutation {
    createFeature(input: CreateFeatureInput!): Feature!
    deleteFeature(featureId: ID!): Boolean!
}
```

#### GraphQL Controller Pattern
**Location**: `graphql/src/main/kotlin/com/maum/backend/controller/{domain}/`

```kotlin
@Controller
class FeatureController(
    private val featureService: FeatureService,
    private val userService: UserService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun features(
        @UserId userId: String,
        @Argument limit: Int?,
        @Argument offset: Int?,
    ): List<FeatureResponse> {
        val response = featureService.getFeatures(userId, limit ?: 20, offset ?: 0)
        return response.featuresList.map { it.toResponse() }
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun createFeature(
        @UserId userId: String,
        @Argument input: CreateFeatureInput,
    ): FeatureResponse {
        val response = featureService.createFeature(userId, input.name)
        return response.feature.toResponse()
    }
}
```

